      'import java.util.*;\n\nList<Integer> numbers = Arrays.asList(5, 2, 8, 1, 9, 3, 6, 4, 7);\n\n// Count\nlong count = numbers.stream()\n    .count();\nSystem.out.println("Count: " + count);\n\nlong evenCount = numbers.stream()\n    .filter(n -> n % 2 == 0)\n    .count();\nSystem.out.println("Even count: " + evenCount);\n\n// Min\nOptional<Integer> min = numbers.stream()\n    .min(Integer::compareTo);\nmin.ifPresent(n -> System.out.println("Min: " + n)); // 1\n\n// Max\nOptional<Integer> max = numbers.stream()\n    .max(Integer::compareTo);\nmax.ifPresent(n -> System.out.println("Max: " + n)); // 9\n\n// With custom comparator\nList<String> names = Arrays.asList("Alice", "Bob", "Charlie", "David");\n\nOptional<String> shortest = names.stream()\n    .min(Comparator.comparing(String::length));\nshortest.ifPresent(s -> System.out.println("Shortest name: " + s)); // Bob\n\nOptional<String> longest = names.stream()\n    .max(Comparator.comparing(String::length));\nlongest.ifPresent(s -> System.out.println("Longest name: " + s)); // Charlie\n\n// With objects\nclass Person {\n    String name; int age;\n    Person(String n, int a) { name = n; age = a; }\n    public String toString() { return name + "(" + age + ")"; }\n}\n\nList<Person> people = Arrays.asList(\n    new Person("Alice", 25),\n    new Person("Bob", 30),\n    new Person("Charlie", 22),\n    new Person("David", 35)\n);\n\nOptional<Person> youngest = people.stream()\n    .min(Comparator.comparingInt(p -> p.age));\nyoungest.ifPresent(p -> System.out.println("Youngest: " + p));\n\nOptional<Person> oldest = people.stream()\n    .max(Comparator.comparingInt(p -> p.age));\noldest.ifPresent(p -> System.out.println("Oldest: " + p));',
