      'import java.util.*;\nimport java.util.stream.*;\n\nclass Employee {\n    String name; String dept; double salary; int age; String gender;\n    Employee(String n, String d, double s, int a, String g) {\n        name = n; dept = d; salary = s; age = a; gender = g;\n    }\n    public String toString() { return name; }\n}\n\nList<Employee> employees = Arrays.asList(\n    new Employee("Alice", "IT", 75000, 25, "F"),\n    new Employee("Bob", "IT", 85000, 32, "M"),\n    new Employee("Charlie", "HR", 65000, 28, "M"),\n    new Employee("Diana", "HR", 70000, 35, "F"),\n    new Employee("Eve", "Finance", 90000, 42, "F"),\n    new Employee("Frank", "Finance", 80000, 38, "M"),\n    new Employee("Grace", "IT", 95000, 29, "F"),\n    new Employee("Henry", "HR", 60000, 24, "M")\n);\n\n// 1. Average salary by department\nMap<String, Double> avgSalaryByDept = employees.stream()\n    .collect(Collectors.groupingBy(e -> e.dept,\n        Collectors.averagingDouble(e -> e.salary)));\nSystem.out.println("Average salary by department: " + avgSalaryByDept);\n\n// 2. Highest paid employee in each department\nMap<String, Optional<Employee>> highestPaidByDept = employees.stream()\n    .collect(Collectors.groupingBy(e -> e.dept,\n        Collectors.maxBy(Comparator.comparingDouble(e -> e.salary))));\nSystem.out.println("\\nHighest paid by department:");\nhighestPaidByDept.forEach((dept, emp) -> \n    System.out.println(dept + ": " + emp.orElse(null)));\n\n// 3. Total salary cost by gender\nMap<String, Double> totalSalaryByGender = employees.stream()\n    .collect(Collectors.groupingBy(e -> e.gender,\n        Collectors.summingDouble(e -> e.salary)));\nSystem.out.println("\\nTotal salary by gender: " + totalSalaryByGender);\n\n// 4. Employees above average salary\nDouble avgOverall = employees.stream()\n    .mapToDouble(e -> e.salary)\n    .average()\n    .orElse(0);\n\nList<Employee> aboveAvg = employees.stream()\n    .filter(e -> e.salary > avgOverall)\n    .collect(Collectors.toList());\nSystem.out.println("\\nAbove average salary (" + avgOverall + "): " + aboveAvg);\n\n// 5. Department statistics\nMap<String, DoubleSummaryStatistics> deptStats = employees.stream()\n    .collect(Collectors.groupingBy(e -> e.dept,\n        Collectors.summarizingDouble(e -> e.salary)));\nSystem.out.println("\\nDepartment statistics:");\ndeptStats.forEach((dept, stats) -> \n    System.out.println(dept + ": count=" + stats.getCount() +\n        ", avg=" + stats.getAverage() +\n        ", max=" + stats.getMax()));\n\n// 6. Employee names sorted by age\nList<String> namesByAge = employees.stream()\n    .sorted(Comparator.comparingInt(e -> e.age))\n    .map(e -> e.name)\n    .collect(Collectors.toList());\nSystem.out.println("\\nEmployees by age: " + namesByAge);',
