    codeSolution:
      'import java.util.*;\nimport java.util.stream.*;\nimport java.time.*;\n\nclass Sale {\n    String product; String category; double amount; LocalDate date; String region;\n    Sale(String p, String c, double a, LocalDate d, String r) {\n        product = p; category = c; amount = a; date = d; region = r;\n    }\n    public String toString() { return product + "($" + amount + ")"; }\n}\n\nList<Sale> sales = Arrays.asList(\n    new Sale("Laptop", "Electronics", 1200, LocalDate.of(2024, 1, 15), "North"),\n    new Sale("Mouse", "Electronics", 25, LocalDate.of(2024, 1, 16), "South"),\n    new Sale("Desk", "Furniture", 350, LocalDate.of(2024, 1, 17), "North"),\n    new Sale("Chair", "Furniture", 150, LocalDate.of(2024, 1, 18), "West"),\n    new Sale("Phone", "Electronics", 800, LocalDate.of(2024, 1, 19), "South"),\n    new Sale("Tablet", "Electronics", 500, LocalDate.of(2024, 1, 20), "North"),\n    new Sale("Monitor", "Electronics", 300, LocalDate.of(2024, 1, 21), "East"),\n    new Sale("Bookshelf", "Furniture", 200, LocalDate.of(2024, 1, 22), "West")\n);\n\n// 1. Total sales by category\nMap<String, Double> salesByCategory = sales.stream()\n    .collect(Collectors.groupingBy(s -> s.category,\n        Collectors.summingDouble(s -> s.amount)));\nSystem.out.println("Sales by category: " + salesByCategory);\n\n// 2. Top 3 products by sales amount\nList<String> topProducts = sales.stream()\n    .sorted(Comparator.comparingDouble(Sale::amount).reversed())\n    .limit(3)\n    .map(s -> s.product + "($" + s.amount + ")")\n    .collect(Collectors.toList());\nSystem.out.println("\\nTop 3 products: " + topProducts);\n\n// 3. Average sale amount by region\nMap<String, Double> avgByRegion = sales.stream()\n    .collect(Collectors.groupingBy(s -> s.region,\n        Collectors.averagingDouble(s -> s.amount)));\nSystem.out.println("\\nAverage by region: " + avgByRegion);\n\n// 4. Sales by month\nMap<YearMonth, Double> salesByMonth = sales.stream()\n    .collect(Collectors.groupingBy(\n        s -> YearMonth.from(s.date),\n        Collectors.summingDouble(s -> s.amount)\n    ));\nSystem.out.println("\\nSales by month: " + salesByMonth);\n\n// 5. Products with sales above average\nDouble avgSale = sales.stream()\n    .mapToDouble(s -> s.amount)\n    .average()\n    .orElse(0);\n\nList<String> highValueProducts = sales.stream()\n    .filter(s -> s.amount > avgSale)\n    .map(s -> s.product)\n    .distinct()\n    .collect(Collectors.toList());\nSystem.out.println("\\nHigh value products (>$" + avgSale + "): " + highValueProducts);\n\n// 6. Category with highest total sales\nMap.Entry<String, Double> topCategory = sales.stream()\n    .collect(Collectors.groupingBy(s -> s.category,\n        Collectors.summingDouble(s -> s.amount)))\n    .entrySet().stream()\n    .max(Map.Entry.comparingByValue())\n    .orElse(null);\nSystem.out.println("\\nTop category: " + topCategory);',
    hint: "Streams are perfect for business data analysis",
